DROP TABLE IF EXISTS messages CASCADE;
DROP TABLE IF EXISTS conversations CASCADE;
DROP TABLE IF EXISTS fans CASCADE;
DROP TABLE IF EXISTS girls CASCADE;
DROP TABLE IF EXISTS personas CASCADE;
DROP TABLE IF EXISTS users CASCADE;
DROP TABLE IF EXISTS girl_daily_limits CASCADE;

CREATE TABLE girls (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  timezone TEXT NOT NULL,
  awake_start TEXT NOT NULL,
  awake_end TEXT NOT NULL,
  default_fan_daily_cap INT NOT NULL DEFAULT 10,
  max_fan_daily_cap INT NOT NULL DEFAULT 20,
  global_daily_cap INT NOT NULL DEFAULT 150,
  messages_sent_today INT NOT NULL DEFAULT 0,
  messages_sent_date DATE NOT NULL DEFAULT CURRENT_DATE
);

CREATE TABLE fans (
  fan_id TEXT PRIMARY KEY,
  fan_name TEXT,
  fan_nick TEXT NOT NULL DEFAULT 'sir',
  girl_id TEXT REFERENCES girls(id),
  manual_mode BOOLEAN NOT NULL DEFAULT false,
  label TEXT,
  summary_text TEXT,
  last_summarized_at TIMESTAMPTZ,
  daily_reply_cap INT NOT NULL DEFAULT 10,
  replies_today INT NOT NULL DEFAULT 0,
  replies_today_date DATE
);

CREATE TABLE conversations (
  fan_id TEXT PRIMARY KEY REFERENCES fans(fan_id),
  girl_id TEXT REFERENCES girls(id),
  last_message_at TIMESTAMPTZ,
  pending_reply BOOLEAN NOT NULL DEFAULT false
);

CREATE TABLE messages (
  id SERIAL PRIMARY KEY,
  conversation_id TEXT REFERENCES conversations(fan_id),
  role TEXT NOT NULL CHECK (role IN ('fan','girl')),
  content TEXT NOT NULL,
  platform_message_id TEXT UNIQUE,
  created_at TIMESTAMPTZ
);

